import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Plus, Trash2, RotateCcw, ArrowRight, Minus } from 'lucide-react';
import CircularProgress from './CircularProgress';
import { formatTime } from '../utils/time';
import { playTone } from '../utils/soundEngine';
import { SoundId } from '../types';
import { useWakeLock } from '../hooks/useWakeLock';

interface SequenceStep {
  id: string;
  duration: number; // seconds
  label: string;
}

interface SequenceViewProps {
  soundId: SoundId;
}

const SequenceView: React.FC<SequenceViewProps> = ({ soundId }) => {
  // --- State ---
  const [steps, setSteps] = useState<SequenceStep[]>([
    { id: '1', duration: 1500, label: 'Work' },
    { id: '2', duration: 300, label: 'Rest' },
  ]);

  const [activeStepIndex, setActiveStepIndex] = useState<number>(0);
  const [timeLeft, setTimeLeft] = useState<number>(1500);
  const [isRunning, setIsRunning] = useState<boolean>(false);
  const [isPaused, setIsPaused] = useState<boolean>(false);

  const intervalRef = useRef<number | null>(null);

  // --- Wake Lock ---
  useWakeLock(isRunning && !isPaused);

  // --- Timer Logic ---
  useEffect(() => {
    if (isRunning && !isPaused) {
      intervalRef.current = window.setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            // Step Finished
            playTone(soundId);
            handleNextStep();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (intervalRef.current) clearInterval(intervalRef.current);
    }

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [isRunning, isPaused, activeStepIndex, steps, soundId]);

  const handleNextStep = () => {
    if (activeStepIndex < steps.length - 1) {
      // Move to next step
      const nextIndex = activeStepIndex + 1;
      setActiveStepIndex(nextIndex);
      setTimeLeft(steps[nextIndex].duration);
    } else {
      // Sequence Complete
      setIsRunning(false);
      setIsPaused(false);
      setActiveStepIndex(0);
      setTimeLeft(steps[0].duration);
    }
  };

  // --- Handlers ---
  const toggleTimer = () => {
    if (!isRunning) {
      // Starting from scratch or reset
      setIsRunning(true);
      setIsPaused(false);
      if (timeLeft === 0) { // Just in case
          setTimeLeft(steps[activeStepIndex].duration);
      }
    } else {
      setIsPaused(!isPaused);
    }
  };

  const resetSequence = () => {
    setIsRunning(false);
    setIsPaused(false);
    setActiveStepIndex(0);
    setTimeLeft(steps[0].duration);
  };

  // --- Editor Handlers ---
  const addStep = () => {
    const newStep: SequenceStep = {
      id: Date.now().toString(),
      duration: 300,
      label: 'New Step',
    };
    setSteps([...steps, newStep]);
  };

  const removeStep = (id: string) => {
    if (steps.length <= 1) return;
    setSteps(steps.filter(s => s.id !== id));
  };

  const updateStep = (id: string, updates: Partial<SequenceStep>) => {
    setSteps(steps.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const adjustStepDuration = (id: string, amount: number) => {
    const step = steps.find(s => s.id === id);
    if (step) {
      const newDuration = Math.max(10, step.duration + amount); // Min 10s
      updateStep(id, { duration: newDuration });
      // If we are editing the step currently ready to play (and not running), update preview
      if (!isRunning && steps[activeStepIndex].id === id) {
          setTimeLeft(newDuration);
      }
    }
  };

  // --- Render ---

  // 1. RUNNING MODE
  if (isRunning || (activeStepIndex > 0 && isPaused)) {
    const currentStep = steps[activeStepIndex];
    const progress = currentStep.duration > 0 ? timeLeft / currentStep.duration : 0;
    const nextStep = activeStepIndex < steps.length - 1 ? steps[activeStepIndex + 1] : null;

    return (
      <div className="flex flex-col items-center h-full w-full max-w-md mx-auto relative animate-in fade-in zoom-in duration-300">
        {/* Header Indicator */}
        <div className="absolute top-0 w-full flex justify-between px-4 py-2 text-xs text-white/40 uppercase tracking-widest font-medium z-10">
            <span>Seq Running</span>
            <span>{activeStepIndex + 1} / {steps.length}</span>
        </div>

        {/* Main Circle */}
        <div className="flex-1 min-h-0 w-full flex flex-col justify-center items-center py-2 relative">
            <CircularProgress progress={progress} color="text-purple-400">
                <div className="text-5xl sm:text-6xl font-mono font-bold tracking-wider text-white drop-shadow-2xl">
                    {formatTime(timeLeft)}
                </div>
                <div className="text-purple-300 mt-2 text-sm sm:text-base font-medium tracking-wider">
                    {currentStep.label}
                </div>
            </CircularProgress>

            {/* Next Step Preview */}
            {nextStep && (
                <div className="absolute bottom-4 flex items-center gap-2 text-white/30 text-sm">
                    <span>Next: {nextStep.label}</span>
                    <ArrowRight size={14} />
                    <span>{formatTime(nextStep.duration)}</span>
                </div>
            )}
        </div>

        {/* Controls */}
        <div className="w-full px-4 pb-2 shrink-0">
            <div className="bg-gray-900/40 backdrop-blur-xl border border-white/10 p-4 rounded-[1.5rem] shadow-2xl flex items-center justify-center gap-6">
                 <button 
                    onClick={resetSequence}
                    className="w-14 h-14 rounded-2xl flex items-center justify-center bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                 >
                    <RotateCcw size={20} />
                 </button>

                 <button
                    onClick={toggleTimer}
                    className={`w-20 h-20 rounded-full flex items-center justify-center transition-all active:scale-95 ${
                        isPaused 
                        ? 'bg-green-500/20 text-green-400 border border-green-500/30 hover:bg-green-500/30 shadow-[0_0_20px_rgba(74,222,128,0.2)]' 
                        : 'bg-red-500/20 text-red-400 border border-red-500/30 hover:bg-red-500/30 shadow-[0_0_20px_rgba(239,68,68,0.2)]'
                    }`}
                >
                    {isPaused ? <Play size={32} className="ml-1 fill-current" /> : <Pause size={32} className="fill-current" />}
                 </button>
            </div>
        </div>
      </div>
    );
  }

  // 2. EDITOR MODE
  return (
    <div className="flex flex-col h-full w-full max-w-md mx-auto pt-2 animate-in slide-in-from-bottom-4 duration-500">

      {/* Editor Header */}
      <div className="px-4 pb-4 flex justify-between items-end">
          <div>
            <h2 className="text-xl font-bold text-white tracking-wide">Sequence</h2>
            <p className="text-xs text-white/40 uppercase tracking-wider font-medium">Design your flow</p>
          </div>
          <button 
            onClick={addStep}
            className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-white/10 hover:bg-white/20 text-xs font-semibold text-white/90 transition-colors border border-white/10"
          >
            <Plus size={14} /> Add Step
          </button>
      </div>

      {/* Step List */}
      <div className="flex-1 min-h-0 overflow-y-auto no-scrollbar px-4 space-y-3 pb-20">
        {steps.map((step, index) => (
            <div 
                key={step.id} 
                className="group relative flex flex-col p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all duration-300"
            >
                <div className="flex items-center gap-3 mb-3">
                    <div className="w-6 h-6 rounded-full bg-white/10 flex items-center justify-center text-xs font-mono text-white/50">
                        {index + 1}
                    </div>
                    <input 
                        type="text" 
                        value={step.label}
                        onChange={(e) => updateStep(step.id, { label: e.target.value })}
                        className="bg-transparent border-none text-white font-medium focus:ring-0 p-0 text-base placeholder-white/20 flex-1"
                        placeholder="Step Name"
                    />
                    <button 
                        onClick={() => removeStep(step.id)}
                        className={`text-white/20 hover:text-red-400 transition-colors p-1 ${steps.length <= 1 ? 'opacity-0 pointer-events-none' : ''}`}
                    >
                        <Trash2 size={16} />
                    </button>
                </div>

                {/* Duration Controls */}
                <div className="flex items-center justify-between bg-black/20 rounded-xl p-1.5">
                    <button 
                        onClick={() => adjustStepDuration(step.id, -15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Minus size={14} />
                    </button>

                    <span className="font-mono text-lg font-bold text-white/90 tracking-wider">
                        {formatTime(step.duration)}
                    </span>

                    <button 
                        onClick={() => adjustStepDuration(step.id, 15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                    >
                        <Plus size={14} />
                    </button>
                </div>
            </div>
        ))}
         <div className="h-4"></div> {/* Spacer */}
      </div>

      {/* Floating Action Button for Play */}
      <div className="absolute bottom-4 right-6 left-6 flex justify-center pointer-events-none">
          <button
            onClick={toggleTimer}
            className="pointer-events-auto flex items-center justify-center gap-2 px-8 py-4 rounded-full bg-purple-500 hover:bg-purple-400 text-white font-bold shadow-[0_0_30px_rgba(168,85,247,0.4)] hover:shadow-[0_0_40px_rgba(168,85,247,0.6)] transition-all active:scale-95 border border-white/20 backdrop-blur-md"
          >
            <Play size={20} className="fill-current" />
            <span className="tracking-wide">START SEQUENCE</span>
          </button>
      </div>

    </div>
  );
};

