                    ))}
                </div>
            </div>
        ))}
      </div>

      {/* Floating Action Buttons for Reset and Play (Fixed Position) */}
      <div className="fixed bottom-28 left-0 right-0 flex justify-center items-center gap-4 z-40 pointer-events-none">
          <button 
             onClick={resetEditor}
             className="pointer-events-auto w-14 h-14 rounded-full bg-gray-900/80 border border-white/10 flex items-center justify-center text-white/50 hover:text-white hover:bg-gray-800/80 backdrop-blur-md transition-all shadow-lg"
             title="Reset Sequence"
          >
             <RotateCcw size={20} />
          </button>

          <button
            onClick={toggleTimer}
            className="pointer-events-auto flex items-center justify-center gap-3 px-8 py-4 rounded-full bg-purple-500 hover:bg-purple-400 text-white font-bold shadow-[0_0_30px_rgba(168,85,247,0.4)] hover:shadow-[0_0_40px_rgba(168,85,247,0.6)] transition-all active:scale-95 border border-white/20 backdrop-blur-md"
          >
            <Play size={22} className="fill-current" />
            <span className="tracking-wide">START SEQUENCE</span>
          </button>
      </div>

      {/* Gradient fade at bottom for list */}
      <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-black via-black/90 to-transparent pointer-events-none z-10"></div>

    </div>
  );
