    const nextStep = activeStepIndex < steps.length - 1 ? steps[activeStepIndex + 1] : null;

    return (
      <div className="flex flex-col items-center h-full w-full max-w-md mx-auto relative animate-in fade-in zoom-in duration-300">
        {/* Background Ambient Glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300px] h-[300px] bg-purple-900/20 rounded-full blur-[100px] pointer-events-none"></div>

        {/* Header Indicator */}
        <div className="absolute top-0 w-full flex justify-between px-4 py-2 text-xs text-purple-200/40 uppercase tracking-widest font-medium z-10">
            <span>Royal Sequence</span>
            <span>{activeStepIndex + 1} / {steps.length}</span>
        </div>

        {/* Main Circle */}
        <div className="flex-1 min-h-0 w-full flex flex-col justify-center items-center py-2 relative">
            <CircularProgress progress={progress} color="text-purple-500">
                <div className="text-5xl sm:text-6xl font-mono font-bold tracking-wider text-white drop-shadow-[0_0_15px_rgba(168,85,247,0.5)]">
                    {formatTime(timeLeft)}
                </div>
                <div className="text-purple-300 mt-2 text-sm sm:text-base font-medium tracking-wider">
                    {currentStep.label}
                </div>
            </CircularProgress>

            {/* Next Step Preview */}
            {nextStep && (
                <div className="absolute bottom-4 flex items-center gap-2 text-purple-200/30 text-sm">
                    <span>Next: {nextStep.label}</span>
                    <ArrowRight size={14} />
                    <span>{formatTime(nextStep.duration)}</span>
                </div>
            )}
        </div>

        {/* Controls */}
        <div className="w-full px-4 pb-2 shrink-0">
            <div className="bg-[#130b1b]/80 backdrop-blur-xl border border-purple-500/10 p-4 rounded-[1.5rem] shadow-2xl flex items-center justify-center gap-6">
                 <button 
                    onClick={resetSequence}
                    className="w-14 h-14 rounded-2xl flex items-center justify-center bg-white/5 hover:bg-white/10 text-white/60 hover:text-white transition-colors"
                 >
                    <RotateCcw size={20} />
                 </button>

                 <button
                    onClick={toggleTimer}
                    className={`w-20 h-20 rounded-full flex items-center justify-center transition-all active:scale-95 ${
                        isPaused 
                        ? 'bg-green-500/20 text-green-400 border border-green-500/30 hover:bg-green-500/30 shadow-[0_0_20px_rgba(74,222,128,0.2)]' 
                        : 'bg-red-500/20 text-red-400 border border-red-500/30 hover:bg-red-500/30 shadow-[0_0_20px_rgba(239,68,68,0.2)]'
                    }`}
                >
                    {isPaused ? <Play size={32} className="ml-1 fill-current" /> : <Pause size={32} className="fill-current" />}
                 </button>
            </div>
        </div>
      </div>
    );
  }

  // 2. EDITOR MODE
  return (
    <div className="flex flex-col h-full w-full max-w-md mx-auto pt-2 animate-in slide-in-from-bottom-4 duration-500 relative">

      {/* Background Ambience */}
      <div className="absolute top-20 left-10 w-64 h-64 bg-purple-900/30 rounded-full blur-[80px] pointer-events-none"></div>
      <div className="absolute bottom-40 right-10 w-48 h-48 bg-indigo-900/20 rounded-full blur-[60px] pointer-events-none"></div>

      {/* Editor Header */}
      <div className="px-4 pb-4 flex justify-between items-end relative z-10">
          <div className="flex items-center gap-3">
             <div>
                <h2 className="text-xl font-bold text-white tracking-wide drop-shadow-md">Sequence</h2>
                <p className="text-xs text-purple-300/40 uppercase tracking-wider font-medium">Design your flow</p>
             </div>
          </div>
          <button 
            onClick={addStep}
            className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-purple-500/10 hover:bg-purple-500/20 text-xs font-semibold text-purple-200 hover:text-white transition-colors border border-purple-500/20 shadow-[0_0_10px_rgba(168,85,247,0.1)]"
          >
            <Plus size={14} /> Add Step
          </button>
      </div>

      {/* Step List */}
      <div className="flex-1 min-h-0 overflow-y-auto no-scrollbar px-4 space-y-3 pb-48 relative z-10">
        {steps.map((step, index) => (
            <div 
                key={step.id} 
                className="group relative flex flex-col p-4 rounded-2xl bg-[#1a1025] border border-purple-500/10 hover:border-purple-500/30 transition-all duration-300 shadow-lg hover:shadow-[0_0_20px_rgba(88,28,135,0.15)]"
            >
                {/* Top Row: Index, Name, Delete */}
                <div className="flex items-center gap-3 mb-3">
                    <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-purple-500/20 flex items-center justify-center text-xs font-mono text-purple-300">
                        {index + 1}
                    </div>
                    <input 
                        type="text" 
                        value={step.label}
                        onChange={(e) => updateStep(step.id, { label: e.target.value })}
                        className="bg-transparent border-none text-purple-50 font-medium focus:ring-0 p-0 text-base placeholder-purple-500/20 flex-1"
                        placeholder="Step Name"
                    />
                    <button 
                        onClick={() => removeStep(step.id)}
                        className={`text-purple-500/30 hover:text-red-400 transition-colors p-1 ${steps.length <= 1 ? 'opacity-0 pointer-events-none' : ''}`}
                    >
                        <Trash2 size={16} />
                    </button>
                </div>

                {/* Middle Row: Duration Counter */}
                <div className="flex items-center justify-between bg-black/40 rounded-xl p-1.5 mb-2 border border-white/5">
                    <button 
