                    >
                        <Minus size={14} />
                    </button>

                    <span className="font-mono text-lg font-bold text-white tracking-wider drop-shadow-sm">
                        {formatTime(step.duration)}
                    </span>

                    <button 
                        onClick={() => adjustStepDuration(step.id, 15)}
                        className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/5 hover:bg-white/10 text-white/40 hover:text-white transition-colors"
                    >
                        <Plus size={14} />
                    </button>
                </div>

                {/* Bottom Row: Quick Presets */}
                <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
                    {PRESETS.map((preset) => (
                        <button
                            key={preset}
                            onClick={() => updateStep(step.id, { duration: preset })}
                            className={`flex-shrink-0 px-2.5 py-1 rounded-md text-[10px] font-medium border transition-all ${
                                step.duration === preset
