                            }`}
                        >
                            {preset < 3600 ? `${preset / 60}m` : `${preset / 3600}h`}
                        </button>
                    ))}
                </div>
            </div>
        ))}
      </div>

      {/* Floating Action Buttons for Reset and Play (Fixed Position) */}
      <div className="fixed bottom-28 left-0 right-0 flex justify-center items-center gap-4 z-40 pointer-events-none">
          <button 
             onClick={resetEditor}
             className="pointer-events-auto w-14 h-14 rounded-full bg-[#130b1b]/90 border border-purple-500/20 flex items-center justify-center text-purple-300/40 hover:text-purple-200 hover:bg-[#1a0f2e] backdrop-blur-md transition-all shadow-lg hover:shadow-purple-900/20"
