                            : 'bg-red-500/10 border-red-500/20 text-red-400 hover:bg-red-500/20 shadow-[0_0_15px_rgba(239,68,68,0.1)]'
                        } ${glassButton}`}
                    >
                        {isPaused ? <Play size={24} className="ml-1 fill-current" /> : <Pause size={24} className="fill-current" />}
                    </button>
                </div>
            </div>
        </div>
      </div>
    );
  }

  // 2. EDITOR MODE
  return (
    <div className="flex flex-col h-full w-full max-w-md mx-auto pt-2 animate-in slide-in-from-bottom-4 duration-500 relative">

      {/* Editor Header */}
      <div className="px-4 pb-4 flex justify-between items-end relative z-10 shrink-0">
          <div className="flex items-center gap-3">
             <div>
                <h2 className="text-xl font-bold text-white tracking-wide">Sequence</h2>
                <p className="text-xs text-white/40 uppercase tracking-wider font-medium">Design your flow</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
            <button 
                onClick={() => setIsBulkMode(!isBulkMode)}
                className={`flex items-center justify-center w-8 h-8 rounded-lg transition-colors border ${
                    isBulkMode 
                    ? 'bg-white/20 text-white border-white/20' 
                    : 'bg-white/10 text-white/60 hover:text-white border-white/10'
                }`}
                title="Bulk Add Steps"
            >
                {isBulkMode ? <X size={14} /> : <Layers size={14} />}
            </button>
            <button 
                onClick={addStep}
                className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-white/10 hover:bg-white/20 text-xs font-semibold text-white/90 transition-colors border border-white/10"
            >
                <Plus size={14} /> Add Step
            </button>
          </div>
      </div>

      {/* Bulk Add Dropdown Expansion */}
      {isBulkMode && (
          <div className="px-4 mb-4 shrink-0 animate-in slide-in-from-top-2 duration-200">
              <div className="bg-[#111] border border-white/10 rounded-2xl p-4 shadow-xl">
                  <div className="flex items-center justify-between mb-4">
                      <span className="text-sm font-medium text-white/70">Number of Steps</span>
                      <div className="flex items-center gap-3 bg-white/5 rounded-lg p-1">
                          <button onClick={() => setBulkCount(Math.max(1, bulkCount - 1))} className="p-1 hover:text-white text-white/50"><Minus size={16} /></button>
                          <span className="font-mono w-6 text-center text-white font-bold">{bulkCount}</span>
                          <button onClick={() => setBulkCount(Math.min(50, bulkCount + 1))} className="p-1 hover:text-white text-white/50"><Plus size={16} /></button>
                      </div>
                  </div>

                  <div className="flex items-center justify-between mb-6">
                      <span className="text-sm font-medium text-white/70">Duration per Step</span>
                      <div className="flex items-center gap-3 bg-white/5 rounded-lg p-1">
                          <button onClick={() => setBulkDuration(Math.max(60, bulkDuration - 60))} className="p-1 hover:text-white text-white/50"><Minus size={16} /></button>
                          <span className="font-mono w-16 text-center text-white font-bold">{formatTime(bulkDuration)}</span>
                          <button onClick={() => setBulkDuration(bulkDuration + 60)} className="p-1 hover:text-white text-white/50"><Plus size={16} /></button>
                      </div>
                  </div>

                  <button 
                    onClick={createBulkSequence}
                    className="w-full py-3 rounded-xl bg-white/10 hover:bg-white/15 border border-white/10 text-white font-semibold flex items-center justify-center gap-2 transition-all active:scale-[0.98]"
                  >
                      <Check size={16} className="text-green-400" />
                      Create Flow
                  </button>
              </div>
          </div>
      )}

      {/* Step List */}
      <div className="flex-1 min-h-0 overflow-y-auto no-scrollbar px-4 space-y-3 pb-4 relative z-10">
        {steps.map((step, index) => (
            <div 
                key={step.id} 
                className="group relative flex flex-col p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10 transition-all duration-300"
